const XLSX = require('xlsx');
const wb = XLSX.utils.book_new();
const ws = XLSX.utils.aoa_to_sheet([['Summary Data']]);
XLSX.utils.book_append_sheet(wb, ws, 'Summary');
XLSX.writeFile(wb, 'workbook.xlsx');

Workbook wb = new XSSFWorkbook();
Sheet ws = wb.createSheet("Summary");
Row row = ws.createRow(0);
Cell cell = row.createCell(0);
cell.setCellValue("Summary Data");

CREATE TABLE worksheet_summary (
  id INT PRIMARY KEY,
  title VARCHAR(255),
  sheet_name VARCHAR(50)
);
INSERT INTO worksheet_summary VALUES (1, 'Summary Data', 'Summary');
